pub fn analyze(text: &str) -> AnalysisResult {
    let wc = word_count(text);
    let counts_init = initial_counts();

    if wc < HP.short_text_word_count {
        return AnalysisResult {
            score: HP.score_max,
            band: "clean".to_string(),
            word_count: wc,
            violations: vec![],
            counts: counts_init,
            total_penalty: 0,
            weighted_sum: 0.0,
            density: 0.0,
            advice: vec![],
        };
    }

    let lines: Vec<&str> = text.split('\n').collect();
    let sentences: Vec<String> = SENTENCE_SPLIT_RE
        .split(text)
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .collect();

    let mut violations: Vec<Violation> = Vec::new();
    let mut advice: Vec<String> = Vec::new();
    let mut counts = counts_init;

    // 1. Slop words
    merge_output(
        &mut violations,
        &mut advice,
        &mut counts,
        rule_slop_words(text),
    );
    // 2. Slop phrases
    merge_output(
        &mut violations,
        &mut advice,
        &mut counts,
        rule_slop_phrases(text),
    );
    // 3. Structural
    merge_output(
        &mut violations,
        &mut advice,
        &mut counts,
        rule_structural(text, &lines),
    );
    // 4. Tone
    merge_output(&mut violations, &mut advice, &mut counts, rule_tone(text));
    // 5. Weasel
